const Q_ECONOMICS_2011=[{"id": "objective>Economics>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks about the subject being done. Given the context, the subject is Economics. </div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An effective way of controlling inflation in a mixed economy is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase productivity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce income tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ration available output </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase imports</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mixed economy is an economic system in which both the state and private sector direct the economy, reflecting characteristics of both market economies and planned economies.  <br/>  A feature of mixed economies is that they tend to lean more toward government control and less toward individual freedoms. Sometimes, government regulation requirements may cost a company so much that it puts it out of business. Conversely, in periods of inflation, government call also make decisions to increase productivity.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the limitations of PPC assumption is that there is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no indication of technological development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no recognition of preferred goods for countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical inefficiency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">abundant resources </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Production Possibility Curve (PPC) is a model that shows alternative ways that an economy can use its scarce resources. One of the assumptions of the PPC is that technology is constant and does not change. Therefore, it does not indicate technological development. This is a limitation because in reality, technology is always advancing and this can increase the productive efficiency of an economy.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of the arithmetic mean is that it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not useful for large data</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not suitable for further statistical analysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cumbersome to determine the actual value </div>", "<div style=\"font-family:Cambria;font-size:17px;\">affected by extreme data</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Arithmetic mean is affected by extreme data, and as such can really alter it's significance e.g 2,3,4,5,3,3,3,5,3,4,<strong>34</strong>,2. </div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Demand patterns are determined by the market on the basis of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scale of preference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer sovereignty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer rationality </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of the commodity </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand patterns are predictions on how consumers react to different products and services in the market. One of the major tools that affects demand patterns is consumer sovereignty. In consumer sovereignty it is believed that the desires and needs of consumers control the output of producers..</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer surplus measures the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">benefits derived from consuming a cheap commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess of total expenditure over total utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difference between marginal utility and marginal cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess of marginal utility over price</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer surplus is the difference between the total amount that consumers are willing and able to pay for a good or service ; indicated by the demand curve and the total amount that they actually do pay i.e. the market price.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER SURPLUS"}, {"id": "objective>Economics>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand for one commodity excludes another, it is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complementary demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived demand</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">competitive demand is a market situation where a prospective buyer could choose between two competing products and still receive roughly the same level of satisfaction. The selection of one product which are normally substitutes would lead to the exclusion of the other product. Example if mr X intends to buy detergent, he can either choose to buy omo or sunlight detergent but not the two. Choosing between these two alternatives is what is referred to as competitive demand.</div>", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price(₦)</td><td style=\"border:1px solid black;text-align:center;\">Quantity</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">120</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">150</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">180</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">200</td></tr></table></div> The graph of the schedule above will depict </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a kinked demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a normal demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an abnormal demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a diminishing marginal utility curve</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The table above represent abnormal demand curve because as prices increases, the quantity demanded also increase. Abnormal demand curve gives reverse to the law of demand which states that \"at higher price,  more quantity will be demanded\".</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The median of an odd-numbered set of scores is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">middle value in the set</div>", "<div style=\"font-family:Cambria;font-size:17px;\">highest value in the set</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arithmetic mean of the set</div>", "<div style=\"font-family:Cambria;font-size:17px;\">most frequently occurring score</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The median is a measure of central tendency that represents the middle value in a set of data when the data is arranged in ascending or descending order. In an odd-numbered set, the median is the exact middle value.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If demand increases without a change in supply, equilibrium price and quantity will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift inward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand for a commodity increases while supply remains constants,  there will be ab excess demand over supply.  This will lead to an increase in the equilibrium price of the commodity as well as an increase in the equilibrium of quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of production, total output is at maximum when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MP = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MP > 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AP = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AP > 0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of production, total output is at maximum when Marginal Product (MP) equals zero. Marginal Product (MP) is the additional output produced by employing one more unit of a factor of production, keeping other factors constant. When MP is zero, it means that adding more units of the factor of production does not increase total output anymore, hence total output is at its maximum.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"><strong>Price</strong></td><td style=\"border:1px solid black;text-align:center;\"><strong>Qty. /(bags)</strong></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> 60</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">120</td></tr></table></div> From the table above, the price elasticity of supply is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elasticity of supply = % change in quantity supplied/ % change in price  <br/>  <br/>  % change in quantity supplied = 120 - 60 /60 × 100% = 100%  <br/>  <br/>  % change in price  = 2- 1 / 1 × 100% = 100%  <br/>  <br/>  Elasticity of supply = 100/100 <br/>  <br/>  = 1</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a consumer is at equilibrium, the MRS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">xy</span> is equal to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sum of the two prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product of the two prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ratio of the two prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difference of the two prices</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If MRSXY < PX/PY, it means that the consumer is willing to pay less for X than the price prevailing in the market. It induces the consumer to buys less of X and more of Y. As a result, MRS rises till it becomes equal to the ratio of prices and the equilibrium is established.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION (MRS)"}, {"id": "objective>Economics>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum price legislation by government will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce demand and create surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase demand and create scarcity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimum price legislation are set above the equilibrium price and there will be excess supply over demand also there will be inflationary pressure from price increase.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ranking is the method used in measuring </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cardinal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinal utility is the notion that utility; the satisfaction of wants and needs achieved through the consumption of goods and services is measured by a ranking of preferences (first, second, third, etc.) that are only comparable on a relative basis. Ordinal utility does not presume that satisfaction is a measurable characteristic of a person, like height or weight, that can be compared against an established benchmark. The contrasting notion is cardinal utility, which is based on a numerical standard.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a firm is faced with an elastic supply curve, its revenue will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be supplied at a higher price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double at a higher price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase by more than the percentage increase in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal percentage change in price </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a product is elastic and its price rises, total revenue decreases. When a product is inelastic and its price rises, total revenue increases. When a product is inelastic and its price falls, total revenue decreases. When a product is unit elastic and its price changes, total revenue remains constant.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The optimal range of output for a perfectly competitive firm is where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AC is lowest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AVC is lowest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC is rising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC is falling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfectly competitive market, the optimal (profit-maximizing) range of output for a firm is where: <br/> Marginal Cost (MC) is rising <br/>  <br/> And Price = MC (because Price = Marginal Revenue in perfect competition) <br/>  <br/> When MC is rising, and the firm produces up to the point where MC = MR (Price), it ensures maximum profit or minimum loss.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm will experience diseconomics of scale when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there are difficulties in coordinating production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is shortage in labour supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the size of market is small</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is an increase in the price of raw materials </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diseconomies of scale happen when a company or business grows so large that the costs per unit increase. It takes place when economies of scale no longer function for a firm. With this principle, rather than experiencing continued decreasing costs and increasing output, a firm sees an increase in costs when output is increased. <br/> -  Diseconomies of scale occur when the expansion of output comes with increasing average unit costs. <br/> -  Diseconomies of scale can involve factors internal to an operation or external conditions beyond a firm's control. <br/> -  Diseconomies of scale may result from technical issues in a production process, organizational management issues, or resource constraints on productive inputs</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of variable proportions is applicable only </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in the long-run period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to large-scale enterprises </div>", "<div style=\"font-family:Cambria;font-size:17px;\">to small-scale enterprises </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the short-run period</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of variable proportions also known as law of diminishing returns is applicable in short run only. Because only in the short run one factor can be kept constant as in the long run all factors are variable. Under this law, there is great possibility that the variable factors are applied in varying proportions.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, the optimal point of production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">U</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The optimal point is 'S' because this is the point at which the budget line is tangential to the indifference curve and this is the optimal satisfaction point of the consumer.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If real income increases while nominal income remains the same, it can be inferred that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unemployment rate has decreased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">general prices have fallen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment rate has risen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">general prices have risen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Real income is measured in constant dollars. If prices go up, nominal income (dollar income) being the same, real income goes down. If prices go down, nominal income (dollar income) being the same, real income goes up. Prices being the same, if nominal income (dollar income) goes up, real income goes up.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of oligopoly is the availability of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">few sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">few buyers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a single seller</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An oligopoly is a market form in which a market or industry is dominated by a small number of sellers (oligopolists). </div>", "topic": "MARKET STRUCTURE : OLIGOPOLY"}, {"id": "objective>Economics>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question </strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The average total cost when 20 units are produced is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦20.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦23.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦13.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦15.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average total cost when 20 units are produced is  <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ATC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TC<hr size=\"1\" />Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦15</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question </strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> When 20 units of output is produced TC will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦360</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦460</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦400</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When 20 units of output is produced TC will be  <br/>   <br/> Total cost = ATC × Q  <br/>  <br/>  = 15 × 200 = ₦300.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The profit of a monopolist can be eliminated where price equals</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AFC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AVC</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Profits would be eliminated when price is equal to marginal cost. That is the cost incurred by a firm by producing one additional unit of a product or service. The monopoly would no longer make profits if the price it charges for its product is equal to the additional cost it incurred in producing that good.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bank consolidation policy in Nigeria is a measure to increase </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the capital base of banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment opportunities in banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of branches</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank consolidation is the process by which one banking company takes over or merges with another. This leads to a potential expansion for the merging bank. It is usually done to maintain and reach the required capital base as instituted by the central bank.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the circulation of money without a corresponding increase in output will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a rise in income levels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the circulation of money without a corresponding increase in output will lead to inflation. Inflation is a general increase in prices and fall in the purchasing value of money. When there is more money in circulation than there are goods and services available, the prices of these goods and services tend to rise.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In national income accounts, an item counted as part of government spending is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">salaries and wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scholarship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social welfare</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In national income accounts, government spending includes all government consumption, investment, and transfer payments. Salaries and wages paid by the government to its employees are part of government consumption and hence are counted as part of government spending.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If aggregate demand is lower than total output in an economy, national income will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be at equilibruim </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aggregate demand is the demand for the gross domestic product (GDP) of a country, decrease in aggregate demand will also lead to a surplus, however there will be net effect of a decrease in the real national income.  <br/> </div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : ELEMENTARY THEORY OF INCOME DETERMINATION"}, {"id": "objective>Economics>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the era of barter, money was generally in the form of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">notes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">precious metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the era of barter, money was generally in the form of commodities. Barter is a system of exchange where goods or services are directly exchanged for other goods or services without using a medium of exchange, such as money. Thus, commodities like salt, tea, cattle, and seeds were used as a medium of exchange.</div>", "topic": "MONEY : TYPES OF MONEY"}, {"id": "objective>Economics>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country achieves economic development when there is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in military expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in capacity utilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a sustained increase in per capita income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an even distribution of goods and services</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The development of any country depends on the economic growth the country achieves over a period of time. Economic growth deals about investment and production and also the extent of Gross Domestic Product in a country. Only when this grows, the people will experience growth in the form of improved standard of living, namely economic development.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An indicator of growth in an economy over a period of time is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">GDP gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GDP at factor cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GDP at market price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GDP deflator</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">GDP at market price is the sum total of gross value added (GVA) in production / generation of all goods and services within the country.. GDP is the most commonly used measure of economic activity and serves as a good indicator to track the economic health of a country. Economic growth (GDP growth) refers to the percent change in real GDP, which corrects the nominal GDP figure for inflation. Real GDP is therefore also referred to as inflation-adjusted GDP or GDP in constant prices.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country embarks on deficit financing in order to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce aggregate demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">curb inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulate investment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deficit financing is a fiscal policy tool where a government spends more money than it collects in revenue within a fiscal period, with the difference being made up by borrowing or minting new funds. The primary reason a country embarks on deficit financing is to stimulate investment and boost economic growth, especially during a recession. By spending more on public projects, the government can stimulate demand and encourage private sector investment.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The deflationary gap is defined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X+K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-K</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The deflationary gap is point K as it illustrates the declining aggregate demand often associated with deflation.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What does <strong>X</strong> represents?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Recessionary gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GNP gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inflationary gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deflationary gap</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the inflationary gap since the level of national income exceeds the level of employment</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The import-substitution strategy of industrialization is to encourage</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">domestic production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large-scale production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">importation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exportation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution strategy of industrialization (ISI) is a trade and economic policy which advocates replacing foreign imports with domestic production. ISI is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Upstream oil activities involve the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">management of pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing of refined products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploration of crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining of crude oil </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oil and gas industry is usually divided into three major sectors: upstream, midstream and downstream. The upstream oil sector is also commonly known as the exploration and production (E&P) sector.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural production in Nigeria is constrained by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ineffective use of stabilization measures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor implementation of policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of payments deficit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural production in Nigeria is primarily constrained by poor implementation of policies. This includes policies related to land use, access to credit, agricultural inputs, and marketing. Ineffective use of stabilization measures and inadequate demand can also be constraints, but they are not the primary ones. Balance of payments deficit is more related to international trade and not directly linked to agricultural production.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of NNPC is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oversee the development of the oil sector </div>", "<div style=\"font-family:Cambria;font-size:17px;\">develop the oil producing areas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fix the prices of petroleum products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure regular supply of products</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian National Petroleum Corporation (NNPC) is the oil corporation through which the Federal Government of Nigeria regulates and participates in the country's petroleum industry.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : NNPC"}, {"id": "objective>Economics>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Investing heavily in the agricultural sector will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sufficient food production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a vibrant commodity market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital inflow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stable export prices</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major reasons for investing in the agricultural sector is for sufficient food production that can cater for a population. A farmer's main goal is to produce a good crop and/or healthy animals in order to make a living and to feed the population. Farmers are responsible for all crops and livestock that are needed for us to survive.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrial development in Nigeria can be encouraged through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">signing WTO treaty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granting subsidies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the provision of efficient infrastructure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct government participation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrial development in Nigeria can be encouraged through the provision of efficient infrastructure. Infrastructure such as good roads, stable electricity, and reliable water supply are essential for the smooth running of industries. When these are in place, it can attract more industries to set up in the country, leading to industrial development.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The record of a country's transactions in international trade is her </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of trade</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of payments (BOP) is the method countries use to monitor all international monetary transactions at a specific period of time. Usually, the BOP is calculated every quarter and every calendar year.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transfer of public shareholding in corporations to private enterprises is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concession</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incorporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercialization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatisation involves selling state-owned assets to the private sector. It is argued the private sector tends to run a business more efficiently because of the profit motive. </div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A condition in which official and autonomous exchange rates coexist is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dual exchange rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">managed floating rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market determined exchange rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple exchange rate system</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A dual exchange rate system is a system where a country maintains two exchange rates, an official exchange rate and an autonomous or market-determined exchange rate. This system is often used to control the flow of foreign exchange in and out of the country.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In modern economics, the Malthusian theory of population is ineffective because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">birth control measures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical progress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural disasters</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He wrote that population growth occurs exponentially, so it increases according to birth rate. For example, if every member of a family tree reproduces, the tree will continue to grow with each generation. On the other hand, food production increases arithmetically, so it only increases at given points in time. Malthus wrote that, left unchecked, populations can outgrow their resources. </div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum population enables an economy to attain the highest level of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income per head</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic development</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum population has been defined as that size of population enabling per capita output of the maximum orders accompanied by the highest possible standards of living under a given set of economic and technological conditions. Therefore, optimum population lies between two extremes, i.e. over-population and under-population.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change from one industry to another by a worker is an example  of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">geographical mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">professional advancement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical mobility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Horizontal mobility refers to the movement of a worker from one job to another within the same occupational category or industry. It is a change in job at the same level. Geographical mobility refers to the movement of a worker from one location to another. Professional advancement refers to the upward movement in one's career, while vertical mobility refers to the upward or downward movement in one's job status or position.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The money paid per hour for work done is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">salary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wage rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money paid per hour for work done is referred to as the wage rate. A wage is a compensation, usually financial, received by workers in exchange for their labor. When it is paid per hour, it is called a wage rate.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trade takes place because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inefficiency in production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative advantage</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> A country is said to have a comparative advantage in the production of a good if it can produce cloth at a lower opportunity cost than another country, this aid International Trade.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The World Trade Organization is responsible for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stabilizing and harmonizing oil prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring equal participation of countries in trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modernising world economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimizing obstacles to international trade and investment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">WTO seeks do the following : minimize obstacles to international trade and investment by standards, settle disputes and reduce trade tensions, stimulate economic growth and employment, cut the cost of doing business internationally, encourage good governance and help countries develop.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}];
